fun build(prefix: String, value: Int): String {
    val sb = StringBuilder()
    sb.append(prefix + ": " + value)
    return sb.toString()
}

fun build(prefix: String, value: Int): String {
    val sb = StringBuffer()
    sb.append(prefix + value)
    return sb.toString()
}

fun build(prefix: String, value: Int): String {
    val sb = StringBuilder()
    sb.append(prefix).append(": ").append(value)
    return sb.toString()
}

fun build(value: Int): String {
    val sb = StringBuilder()
    sb.append("value: ")
    sb.append(value)
    return sb.toString()
}

fun build(prefix: String, value: Int): String =
    buildString {
        append(prefix)
        append(": ")
        append(value)
    }
